def select_missing_candidates(document):
    selected = []
    for row in document["candidates"]:
        if row["certified_resolved"] is True and row["gold_equivalent_after_terminal_lf_normalization"] is False and row["outcome_complete"] is False and row["status"] == "certified_unadjudicated":
            selected.append(row)
    return selected

def select_missing_candidates(document):
    selected = []
    for row in document.get("candidates", []):
        if row.get("certified_resolved") is True and row.get("gold_equivalent_after_terminal_lf_normalization") is False and row.get("outcome_complete") is False:
            selected.append(row)
    return selected
